def longest_run_char(s):
    max_length, max_char = 0, ''
    prev_char = None
    for char in s:
        if char == prev_char:
            curr_length = s.count(char) - 1 + (1 if prev_char is None else 0)
            if curr_length > max_length:
                max_length, max_char = curr_length, char
        prev_char = char
    return max_char or ''
